<template>


        <div style="width: 80%">
            <div style="margin-bottom: 30px" >用户详情</div>
            <el-form :inline="true" :model="form"  label-width="100px">
                <el-form-item label="卡号">
                    <el-input v-model="form.username" disabled></el-input>
                </el-form-item>
                <el-form-item label="姓名">
                    <el-input v-model="form.name" disabled></el-input>
                </el-form-item>
                <el-form-item label="年龄">
                    <el-input v-model="form.age" disabled></el-input>
                </el-form-item>
                <el-form-item label="性别">
                    <el-input v-model="form.sex" disabled></el-input>
                </el-form-item>
                <el-form-item label="联系方式">
                    <el-input v-model="form.phone" disabled></el-input>
                </el-form-item>
                <el-form-item label="地址">
                    <el-input v-model="form.address" disabled></el-input>
                </el-form-item>
                <el-form-item label="创建时间">
                    <el-input v-model="form.createtime" disabled></el-input>
                </el-form-item>
                <el-form-item label="更新时间">
                    <el-input v-model="form.updatetime" disabled></el-input>
                </el-form-item>

            </el-form>
            <div style="text-align: center; margin-top: 30px">
                <el-button type="primary" @click="save">确认</el-button>
                <!--            <el-button type="danger ">取消</el-button>-->
            </div>
        </div>
</template>

<script>
    import request from "@/utils/request";
    export default {
        name: "DetailUser",
        data(){
            return {
                form: {

                }
            }

        },
        created() {
            const id = this.$route.query.id
            request.get("/user/" + id).then(res =>{
                this.form = res.data;
            })
        },
        methods: {
            save() {
                request.put('/user/update',this.form).then(res =>{
                    if(res.code === '200'){
                        // this.$notify.success('更新成功')
                        this.$router.push("/user")
                    }else{
                        this.$notify.error(res.msg)
                    }
                })
                //    对接的是后台的UserController.java文件的路径
            }
        }
    }
</script>
